// src/components/Auth/LoginPage.js
import React, { useState } from 'react';
import { Lock, Phone, KeyRound } from 'lucide-react';
import '../../styles/LoginPage.css';

const LoginPage = ({ onLogin }) => {
  const [mobile, setMobile] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    const result = await onLogin(mobile, password);
    
    if (!result.success) {
      setError(result.message);
      setLoading(false);
    }
  };

  return (
    <div className="login-container">
      <div className="login-card">
        <div className="login-header">
          <div className="login-icon">
            <Lock size={40} />
          </div>
          <h1 className="login-title">MakhanChor</h1>
          <p className="login-subtitle">Dashboard Access</p>
        </div>

        <form onSubmit={handleSubmit} className="login-form">
          <div className="input-group">
            <label>Mobile Number</label>
            <div className="input-wrapper">
              <Phone className="input-icon" size={20} />
              <input
                type="tel"
                inputMode="numeric"
                maxLength="10"
                value={mobile}
                onChange={(e) => {
                  setMobile(e.target.value);
                  setError('');
                }}
                placeholder="Enter mobile number"
                required
                autoFocus
              />
            </div>
          </div>

          <div className="input-group">
            <label>Password</label>
            <div className="input-wrapper">
              <KeyRound className="input-icon" size={20} />
              <input
                type="password"
                value={password}
                onChange={(e) => {
                  setPassword(e.target.value);
                  setError('');
                }}
                placeholder="Enter password"
                required
              />
            </div>
            {error && <p className="error-message">{error}</p>}
          </div>

          <button type="submit" disabled={loading} className="login-button">
            {loading ? 'Logging in...' : 'Login'}
          </button>
        </form>

        <p className="login-footer">Secured access for authorized personnel only</p>
      </div>
    </div>
  );
};

export default LoginPage;
